  <text x="115" y="380" fill="#e4e4e7" font-size="13" text-anchor="middle" font-family="sans-serif">持續</text>
  <text x="115" y="397" fill="#e4e4e7" font-size="13" text-anchor="middle" font-family="sans-serif">持有</text>
